module top_module(
    input clk,
    input reset,   // Synchronous active-high reset
    input [7:0] in_hi,  // Upper byte input for the combinational circuit
    input [7:0] in_lo,  // Lower byte input for the combinational circuit
    output [15:0] out  // Output from the functional module
);// Combinational circuit to combine two input bytes into a half-word
    wire [15:0] half_word = {in_hi, in_lo};

    // 4-digit binary up-counter
    reg [3:0] counter_in;
    reg [15:0] counter_out;

    always @(posedge clk) begin
        if (reset) begin
            counter_in <= 4'b0000;
            counter_out <= 16'b0000000000000000;
        end else begin
            counter_in <= counter_in + 1;
            counter_out <= counter_in;
        end
    end

    // Functional module to output the sum of the half-word and the counter
      wire _n01 = half_word[0] ^ counter_out[0];
  wire _c01 = half_word[0] & counter_out[0];
  wire _n02 = half_word[1] ^ counter_out[1] ^ _c01;
  wire _c02 = (half_word[1] & counter_out[1]) | (half_word[1] & _c01) | (counter_out[1] & _c01);
  wire _n03 = half_word[2] ^ counter_out[2] ^ _c02;
  wire _c03 = (half_word[2] & counter_out[2]) | (half_word[2] & _c02) | (counter_out[2] & _c02);
  wire _n04 = half_word[3] ^ counter_out[3] ^ _c03;
  wire _c04 = (half_word[3] & counter_out[3]) | (half_word[3] & _c03) | (counter_out[3] & _c03);
  assign out = {_n01, _n02, _n03, _n04};

endmodule
